+            descendInto(tableBody)
+            result += "</tbody>\n"
+        }
+    }
+
+    mutating func visitTableRow(_ tableRow: Table.Row) {
+        result += "<tr>\n"
+
+        currentTableColumn = 0
+        descendInto(tableRow)
+
+        result += "</tr>\n"
+    }
+
+    mutating func visitTableCell(_ tableCell: Table.Cell) {
